def compute_factor(net_profit, market_cap):
    factor = net_profit / market_cap
    return factor

def compute_factor(adjusted_profit, market_cap):
    factor = adjusted_profit / market_cap
    return factor

def compute_factor(total_owner_equities, market_cap):
    factor = total_owner_equities / market_cap
    return factor

def compute_factor(operating_revenue, market_cap):
    factor = operating_revenue / market_cap
    return factor

def compute_factor(roe):
    roe_growth_rate = roe.pct_change(periods=252)
    return roe_growth_rate

def compute_factor(money):
    avg_daily_turnover = money.rolling(window=20, min_periods=1).mean()
    return avg_daily_turnover

def compute_factor(operating_revenue):
    revenue = operating_revenue
    return revenue

def compute_factor(net_profit, total_assets):
    factor = net_profit / total_assets
    return factor

def compute_factor(operating_profit, total_profit):
    ratio = operating_profit / total_profit
    return ratio

def compute_factor(inc_revenue_year_on_year):
    factor = inc_revenue_year_on_year.rolling(window=60, min_periods=1).mean()
    return factor

def compute_factor(inc_total_revenue_annual):
    factor = inc_total_revenue_annual.rolling(window=120, min_periods=1).mean()
    return factor

def compute_factor(inc_revenue_annual):
    factor = inc_revenue_annual
    return factor

def compute_factor(inc_net_profit_annual):
    factor = inc_net_profit_annual.rolling(window=90, min_periods=1).mean()
    return factor

def compute_factor(close):
    factor = (close > close.shift(1)).astype(float) - (close < close.shift(1)).astype(float)
    return factor

def compute_factor(gross_profit_margin):
    factor = (gross_profit_margin > gross_profit_margin.shift(1)).astype(float) - (gross_profit_margin < gross_profit_margin.shift(1)).astype(float)
    return factor
